    private void btnAddupdateActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnAddupdateActionPerformed
        // TODO add your handling code here:
        if(txtAproductID.getText().trim().isEmpty() || cmbAcategory.getSelectedItem().toString().isEmpty() || txtAname.getText().trim().isEmpty() ||
                txtAprice.getText().trim().isEmpty()){
            
            JOptionPane.showMessageDialog(this, "Please fill in all required fields","Error",JOptionPane.ERROR_MESSAGE);
            return;
        }
        
String productID = txtAproductID.getText().trim();
String productCategory = cmbAcategory.getSelectedItem().toString();
String productName = txtAname.getText().trim();
String productPrice = txtAprice.getText().trim();

products p1 = new products(productID, productCategory, productName, productPrice) {
    @Override
    protected void displayInformation() {
        throw new UnsupportedOperationException("Not supported yet."); //To change body of generated methods, choose Tools | Templates.
    }
};
String dataLine = productID + "," + productCategory + "," + productName + "," + productPrice;
saveDataToFile(dataLine);

if (pdb.add(p1)) {
    JOptionPane.showMessageDialog(this, "Report Added");
} else {
    JOptionPane.showMessageDialog(this, "Report can't be added");
}
    }//GEN-LAST:event_btnAddupdateActionPerformed

