    private void saveDataToFile(String dataLine) {
    String productID = txtAproductID.getText();
    String productCategory = cmbAcategory.getSelectedItem().toString();
    String productName = txtAname.getText();
    String productPrice = txtAprice.getText();
    
    try {
        String fileName = "Products.txt"; // File name without full path
        FileWriter Writer = new FileWriter(fileName, true);
        Writer.write( productID + " " + productCategory + " " + productName + " " + productPrice);
        Writer.write(System.getProperty("line.separator"));
        Writer.close();
        JOptionPane.showMessageDialog(null, "Successful");
        setVisible(true);
    } catch (IOException ex) {
        JOptionPane.showMessageDialog(this, "Error saving data to file: " + ex.getMessage(), "Error", JOptionPane.ERROR_MESSAGE);
    }
 }
    
